// Procesar adjuntos de cada correo
const items = [];

for (const item of $input.all()) {
  const binaries = item.binary || {};

  // Buscar adjuntos ZIP
  for (const [key, binaryData] of Object.entries(binaries)) {
    if (binaryData.fileName && binaryData.fileName.toLowerCase().endsWith('.zip')) {
      items.push({
        json: {
          email_from: item.json.from?.text || item.json.from || 'Desconocido',
          email_subject: item.json.subject || 'Sin asunto',
          email_date: item.json.date || 'Sin fecha',
          attachment_name: binaryData.fileName,
          has_zip: true
        },
        binary: {
          zip_file: binaryData
        }
      });
    }
  }
}

if (items.length === 0) {
  items.push({ json: { message: 'No se encontraron adjuntos ZIP', has_zip: false } });
}

return items;

const JSZip = require('jszip');
const { parseStringPromise } = require('xml2js');

const results = [];

for (const item of $input.all()) {
  try {
    // Obtener el buffer del ZIP
    const zipBuffer = await this.helpers.getBinaryDataBuffer(item, 'zip_file');
    const zip = await JSZip.loadAsync(zipBuffer);

    let xmlContent = null;
    let pdfFileName = null;
    let xmlFileName = null;

    // Buscar XML y PDF dentro del ZIP
    for (const [filename, file] of Object.entries(zip.files)) {
      if (filename.toLowerCase().endsWith('.xml')) {
        xmlContent = await file.async('text');
        xmlFileName = filename;
      }
      if (filename.toLowerCase().endsWith('.pdf')) {
        pdfFileName = filename;
      }
    }

    if (!xmlContent) {
      results.push({
        json: {
          ...item.json,
          error: 'No se encontró XML en el ZIP',
          nit_emisor: 'N/A',
          razon_social: 'N/A',
          numero_factura: 'N/A',
          fecha_emision: 'N/A',
          valor_total: 0,
          descripcion: 'N/A'
        }
      });
      continue;
    }

    // Parsear XML
    const parsed = await parseStringPromise(xmlContent, {
      explicitArray: false,
      ignoreAttrs: false,
      tagNameProcessors: [(name) => name.split(':').pop()]
    });

    // Detectar si es AttachedDocument o Invoice
    const root = parsed.AttachedDocument || parsed.Invoice || parsed;
    let invoiceData = null;

    let nit = 'N/A';
    let razonSocial = 'N/A';
    let numFactura = 'N/A';
    let fecha = 'N/A';
    let total = 0;
    let descripcion = 'N/A';

    if (parsed.AttachedDocument) {
      // Formato AttachedDocument (factura colombiana)
      const doc = parsed.AttachedDocument;
      numFactura = doc.ID || doc.ParentDocumentID || 'N/A';
      fecha = doc.IssueDate || 'N/A';

      // SenderParty
      const sender = doc.SenderParty;
      if (sender && sender.PartyTaxScheme) {
        nit = sender.PartyTaxScheme.CompanyID?._  || sender.PartyTaxScheme.CompanyID || 'N/A';
        razonSocial = sender.PartyTaxScheme.RegistrationName || 'N/A';
      }

      // Factura embebida en Attachment
      const attachment = doc.Attachment;
      if (attachment && attachment.ExternalReference && attachment.ExternalReference.Description) {
        try {
          const embeddedXml = attachment.ExternalReference.Description;
          const embeddedParsed = await parseStringPromise(embeddedXml, {
            explicitArray: false,
            ignoreAttrs: false,
            tagNameProcessors: [(name) => name.split(':').pop()]
          });

          const invoice = embeddedParsed.Invoice;
          if (invoice) {
            // Total
            if (invoice.LegalMonetaryTotal) {
              const lmt = invoice.LegalMonetaryTotal;
              const payable = lmt.PayableAmount?._ || lmt.PayableAmount || '0';
              total = parseFloat(payable) || 0;
            }

            // Descripción primer item
            let invoiceLine = invoice.InvoiceLine;
            if (invoiceLine) {
              if (Array.isArray(invoiceLine)) invoiceLine = invoiceLine[0];
              if (invoiceLine.Item) {
                descripcion = invoiceLine.Item.Description || invoiceLine.Item.Name || 'N/A';
              }
            }
          }
        } catch(e) {
          // Error al parsear factura embebida
        }
      }
    } else if (parsed.Invoice) {
      // Invoice directo
      const inv = parsed.Invoice;
      numFactura = inv.ID || 'N/A';
      fecha = inv.IssueDate || 'N/A';

      const supplier = inv.AccountingSupplierParty?.Party;
      if (supplier) {
        const taxScheme = supplier.PartyTaxScheme;
        if (taxScheme) {
          nit = taxScheme.CompanyID?._ || taxScheme.CompanyID || 'N/A';
          razonSocial = taxScheme.RegistrationName || 'N/A';
        }
        if (razonSocial === 'N/A' && supplier.PartyLegalEntity) {
          razonSocial = supplier.PartyLegalEntity.RegistrationName || 'N/A';
        }
      }

      if (inv.LegalMonetaryTotal) {
        const payable = inv.LegalMonetaryTotal.PayableAmount?._ || inv.LegalMonetaryTotal.PayableAmount || '0';
        total = parseFloat(payable) || 0;
      }

      let invoiceLine = inv.InvoiceLine;
      if (invoiceLine) {
        if (Array.isArray(invoiceLine)) invoiceLine = invoiceLine[0];
        if (invoiceLine.Item) {
          descripcion = invoiceLine.Item.Description || invoiceLine.Item.Name || 'N/A';
        }
      }
    }

    results.push({
      json: {
        nit_emisor: nit,
        razon_social: razonSocial,
        numero_factura: numFactura,
        fecha_emision: fecha,
        valor_total: total,
        descripcion: descripcion,
        archivo_pdf: pdfFileName || 'No encontrado',
        archivo_xml: xmlFileName || 'No encontrado',
        email_from: item.json.email_from,
        email_subject: item.json.email_subject,
        email_date: item.json.email_date
      }
    });

  } catch (error) {
    results.push({
      json: {
        ...item.json,
        error: `Error procesando: ${error.message}`,
        nit_emisor: 'N/A',
        razon_social: 'N/A',
        numero_factura: 'N/A',
        fecha_emision: 'N/A',
        valor_total: 0,
        descripcion: 'N/A'
      }
    });
  }
}

return results;
